import numpy as np

class AmplitudeEstimationSimulator:
    def __init__(self, num_evaluation_qubits: int = 6):
        self.m = num_evaluation_qubits
        self.M = 2 ** num_evaluation_qubits

    def estimate_amplitude(self, true_amplitude: float) -> dict:
        true_theta = np.arcsin(np.sqrt(true_amplitude)) / np.pi
        # QAE error is O(1/M)
        estimated_theta = true_theta + np.random.normal(0, 1/(2*self.M))
        estimated_amp = np.sin(np.pi * estimated_theta) ** 2
        return {'estimate': estimated_amp, 'error': abs(estimated_amp - true_amplitude), 'oracle_calls': self.M}

    def classical_estimation(self, true_amplitude: float, num_samples: int) -> dict:
        samples = np.random.binomial(1, true_amplitude, num_samples)
        estimate = np.mean(samples)
        error = abs(estimate - true_amplitude)
        return {'estimate': estimate, 'error': error, 'samples': num_samples}

    def compare_methods(self, true_amplitude: float) -> dict:
        quantum = self.estimate_amplitude(true_amplitude)
        classical = self.classical_estimation(true_amplitude, self.M**2)
        return {'quantum': quantum, 'classical': classical, 'speedup': self.M}

import numpy as np
from scipy.stats import norm

class QuantumOptionPricer:
    def __init__(self, num_price_qubits: int = 6):
        self.n_states = 2 ** num_price_qubits

    def discretize_distribution(self, spot: float, rate: float, vol: float, T: float) -> tuple:
        mu = np.log(spot) + (rate - 0.5*vol**2)*T
        sigma = vol*np.sqrt(T)
        log_prices = np.linspace(mu - 4*sigma, mu + 4*sigma, self.n_states)
        prices = np.exp(log_prices)
        probs = norm.pdf(log_prices, mu, sigma)
        probs = probs / probs.sum()
        return prices, probs

    def quantum_price(self, spot: float, strike: float, rate: float, vol: float, T: float, is_call: bool) -> dict:
        prices, probs = self.discretize_distribution(spot, rate, vol, T)
        payoffs = np.maximum(prices - strike, 0) if is_call else np.maximum(strike - prices, 0)
        expected_payoff = np.sum(payoffs * probs)
        price = expected_payoff * np.exp(-rate * T)
        return {'price': price, 'method': 'quantum_inspired'}

    def compare_with_bs(self, spot: float, strike: float, rate: float, vol: float, T: float, is_call: bool) -> dict:
        d1 = (np.log(spot/strike) + (rate + 0.5*vol**2)*T) / (vol*np.sqrt(T))
        d2 = d1 - vol*np.sqrt(T)
        if is_call:
            bs = spot*norm.cdf(d1) - strike*np.exp(-rate*T)*norm.cdf(d2)
        else:
            bs = strike*np.exp(-rate*T)*norm.cdf(-d2) - spot*norm.cdf(-d1)
        quantum = self.quantum_price(spot, strike, rate, vol, T, is_call)
        return {'bs_price': bs, 'quantum_price': quantum['price'], 'error': abs(bs - quantum['price'])}

