import numpy as np

class QuantumAsianPricer:
    def __init__(self, num_steps: int = 50):
        self.num_steps = num_steps

    def generate_path(self, spot: float, rate: float, vol: float, T: float, z: np.ndarray) -> np.ndarray:
        dt = T / self.num_steps
        path = [spot]
        for zi in z:
            drift = (rate - 0.5*vol**2)*dt
            diff = vol*np.sqrt(dt)*zi
            path.append(path[-1]*np.exp(drift + diff))
        return np.array(path)

    def price_asian(self, spot: float, strike: float, rate: float, vol: float, T: float, num_samples: int) -> dict:
        payoffs = []
        for _ in range(num_samples // 2):
            z = np.random.standard_normal(self.num_steps)
            path1 = self.generate_path(spot, rate, vol, T, z)
            path2 = self.generate_path(spot, rate, vol, T, -z)
            payoff1 = max(0, np.mean(path1) - strike)
            payoff2 = max(0, np.mean(path2) - strike)
            payoffs.append((payoff1 + payoff2) / 2)
        price = np.exp(-rate*T) * np.mean(payoffs)
        se = np.exp(-rate*T) * np.std(payoffs) / np.sqrt(len(payoffs))
        return {'price': price, 'std_error': se, 'variance_reduction': 'antithetic'}

