import numpy as np

class VariationalPricer:
    def __init__(self, num_params: int = 10):
        self.num_params = num_params

    def circuit_output(self, params: np.ndarray, features: np.ndarray) -> float:
        encoded = np.tanh(features @ params[:len(features)])
        for i in range(0, len(params) - len(features), 3):
            rot = params[len(features)+i:len(features)+i+3]
            if len(rot) == 3:
                encoded = np.sin(encoded + 0.1*np.sum(rot))
        return float(np.mean(encoded))

    def train(self, data: list, iterations: int = 50, lr: float = 0.1) -> dict:
        params = np.random.randn(self.num_params) * 0.1
        losses = []
        for _ in range(iterations):
            total_loss = 0
            for features, target in data:
                pred = self.circuit_output(params, features) * 50 + 10
                loss = (pred - target) ** 2
                total_loss += loss
                # Numerical gradient
                grad = np.zeros_like(params)
                eps = 0.01
                for i in range(len(params)):
                    p_plus = params.copy(); p_plus[i] += eps
                    p_minus = params.copy(); p_minus[i] -= eps
                    grad[i] = ((self.circuit_output(p_plus, features)*50+10 - target)**2 - (self.circuit_output(p_minus, features)*50+10 - target)**2) / (2*eps)
                params -= lr * grad / len(data)
            losses.append(total_loss / len(data))
        return {'params': params, 'final_loss': losses[-1]}

