import numpy as np
from typing import List, Dict
from scipy.stats import norm

class QuantumPortfolioPricer:
    def __init__(self):
        pass

    def _bs_price(self, spot, strike, rate, vol, T, is_call):
        d1 = (np.log(spot/strike) + (rate + 0.5*vol**2)*T) / (vol*np.sqrt(T))
        d2 = d1 - vol*np.sqrt(T)
        if is_call:
            return spot*norm.cdf(d1) - strike*np.exp(-rate*T)*norm.cdf(d2)
        return strike*np.exp(-rate*T)*norm.cdf(-d2) - spot*norm.cdf(-d1)

    def price_portfolio(self, options: List[Dict], spot: float, rate: float, vol: float) -> dict:
        total = 0
        details = []
        for opt in options:
            price = self._bs_price(spot, opt['strike'], rate, vol, opt['T'], opt['is_call'])
            position_value = price * opt['quantity']
            total += position_value
            details.append({'option': opt, 'price': price, 'position_value': position_value})
        return {'total_value': total, 'details': details, 'quantum_note': 'Parallel pricing of all options'}

    def portfolio_var(self, options: List[Dict], spot: float, rate: float, vol: float, num_scenarios: int) -> dict:
        scenarios = spot * np.exp(np.random.normal(-0.5*vol**2, vol, num_scenarios))
        values = []
        for s in scenarios:
            val = sum(self._bs_price(s, o['strike'], rate, vol, o['T'], o['is_call']) * o['quantity'] for o in options)
            values.append(val)
        current = self.price_portfolio(options, spot, rate, vol)['total_value']
        pnls = np.array(values) - current
        return {'var_95': -np.percentile(pnls, 5), 'var_99': -np.percentile(pnls, 1), 'scenarios': num_scenarios}
